module RefModule(out,clock,in);input in,clock;
output out;
reg out = 0;
reg final_sig = 0;
always @(posedge clock)
	begin
		if(in == 0)
			begin
				out = 0;
				final_sig = 0;
			end
		else if (in == 1 && out == 0 && final_sig == 0) 
			begin 
				out = 1;
				final_sig = 1;
			end
		else if (in == 1 && out == 1)
			begin
				out = 0;
			end
	end
endmodule
